def assess(record: dict) -> str:
    required = {"case_id", "extra_policy", "json_schema", "valid_fixture", "business_rule"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (record.get("extra_policy") == "forbid" and record.get("json_schema") and record.get("valid_fixture") and record.get("business_rule")) else "REJECT_SCHEMA"

valid = {"case_id": "CASO-CUS-042-1A", **{"extra_policy":"forbid","json_schema":True,"valid_fixture":True,"business_rule":True}}
invalid = {**valid, **{"extra_policy": "allow", "business_rule": False}}
incomplete = {k: v for k, v in valid.items() if k != "business_rule"}
print(assess(valid), assess(invalid), assess(incomplete))

